import{_ as s,o as t,c as a,a3 as n}from"./chunks/framework.LBeL10WQ.js";const p=JSON.parse('{"title":"Facturation & Paiements","description":"","frontmatter":{"title":"Facturation & Paiements"},"headers":[],"relativePath":"faq/billing.md","filePath":"faq/billing.md"}'),r={name:"faq/billing.md"};function i(o,e,l,u,d,m){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="facturation-paiements" tabindex="-1">Facturation &amp; Paiements <a class="header-anchor" href="#facturation-paiements" aria-label="Permalink to &quot;Facturation &amp; Paiements&quot;">​</a></h1><details class="details custom-block"><summary>Je ne vois pas mes revenus dans mon Wallet</summary><p>Le crédit n&#39;est pas automatique à la signature, mais à la <strong>réalisation</strong>. Vous devez valider manuellement selon le format :</p><ul><li><strong>Insertion Colis :</strong> Avez-vous rempli votre déclaration de volume hebdomadaire ? (Le lundi ou mardi)</li><li><strong>Email :</strong> Avez-vous cliqué sur <strong>&quot;Valider la diffusion&quot;</strong> après l&#39;envoi ?</li></ul><p>Sans cette action, les fonds restent séquestrés.</p></details><details class="details custom-block"><summary>Comment retirer mes gains et éditer ma facture ?</summary><p>Allez dans <strong>Transaction → Exchange</strong> et cliquez sur <code>Retirer</code>. Saisissez le montant.</p><p><strong>Important :</strong> Si des frais de gestion s&#39;appliquent, éditez votre facture en conséquence du montant net reçu.</p></details><details class="details custom-block"><summary>À partir de quand les revenus sont-ils disponibles ?</summary><p>Le revenu de la campagne est versé au solde de votre compte <strong>30 jours après le dernier reporting</strong>. Choisissez ensuite <code>Transférer vers le wallet</code> ou <code>Retirer</code> vos revenus.</p></details><details class="details custom-block"><summary>Quand sont émis les paiements ?</summary><p>Les paiements sont émis à <strong>30 jours fin de mois</strong>, date de réception de la demande de retrait, à condition que la facture soumise soit valide.</p></details><details class="details custom-block"><summary>Puis-je réinvestir mes gains ?</summary><p>Oui, sans frais. Dans <strong>Exchange</strong>, cliquez sur <code>Transférer vers le wallet</code>. Vous pourrez utiliser ce solde immédiatement pour acheter du trafic pour votre propre site.</p></details><details class="details custom-block"><summary>Pourquoi mes revenus sont-ils bloqués 30 jours ?</summary><p>Le délai de 30 jours est un <strong>délai de protection</strong> qui sécurise votre paiement et celui de l&#39;annonceur.</p><p>Il permet de détecter et traiter les anomalies éventuelles (cartons perdus, volumes non conformes, campagne interrompue) <strong>avant</strong> que les fonds soient définitivement libérés. Sans ce tampon, getinside ne pourrait pas garantir votre paiement en cas d&#39;impayé annonceur.</p></details><details class="details custom-block"><summary>Que se passe-t-il si une anomalie est détectée pendant les 30 jours ?</summary><p>getinside vous contacte directement pour résoudre l&#39;incident. Pendant la résolution, le délai de disponibilité des fonds est suspendu. Une fois l&#39;anomalie traitée, le compteur reprend.</p><p>Dans les cas courants (écart de volume, flyer non conforme), la résolution prend 48 à 72h. Contactez <a href="mailto:support@getinside.fr" target="_blank" rel="noreferrer">support@getinside.fr</a> si vous n&#39;avez pas de retour sous 5 jours ouvrés.</p></details><details class="details custom-block"><summary>Mes fonds peuvent-ils expirer ?</summary><p>Oui. Si vous ne vous connectez pas <strong>et</strong> ne retirez pas vos revenus pendant <strong>12 mois consécutifs</strong>, les fonds disponibles expirent et sont définitivement acquis à getinside.</p><p><strong>Comment éviter cela :</strong> connectez-vous régulièrement, ou activez les notifications de solde dans votre espace compte. Un retrait partiel ou un réinvestissement suffit à réinitialiser le compteur.</p></details>',9)])])}const g=s(r,[["render",i]]);export{p as __pageData,g as default};
